import{gt as e,nt as t,s as n,tt as r}from"./chunks/framework.BqU7tCwc.js";var i=JSON.parse(`{"title":"macOS 使用 /etc/resolver 配置分域 DNS","description":"","frontmatter":{"title":"macOS 使用 /etc/resolver 配置分域 DNS"},"headers":[],"relativePath":"infrastructure/os/mac/resolver.md","filePath":"infrastructure/os/mac/resolver.md","lastUpdated":1784689034000}`),a={name:`infrastructure/os/mac/resolver.md`};function o(n,i,a,o,s,c){return e(),r(`div`,null,[...i[0]||=[t(`<h1 id="macos-使用-etc-resolver-配置分域-dns" tabindex="-1">macOS 使用 <code>/etc/resolver</code> 配置分域 DNS <a class="header-anchor" href="#macos-使用-etc-resolver-配置分域-dns" aria-label="Permalink to “macOS 使用 /etc/resolver 配置分域 DNS”">​</a></h1><p><code>/etc/resolver/</code> 是 macOS 的分域 DNS 配置目录。它可以让指定域名及其子域名使用特定 DNS 服务器，而其他域名仍走系统默认 DNS。</p><p>典型用途：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>公司内网域名  -&gt; 公司或 VPN DNS</span></span>
<span class="line"><span>开发测试域名  -&gt; 本地 DNS</span></span>
<span class="line"><span>其他公网域名  -&gt; 系统默认 DNS</span></span></code></pre></div><h2 id="基本规则" tabindex="-1">基本规则 <a class="header-anchor" href="#基本规则" aria-label="Permalink to “基本规则”">​</a></h2><p>在 <code>/etc/resolver/</code> 下创建与目标域名同名的文件。例如，<code>/etc/resolver/company.internal</code> 的内容如下：</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>nameserver 10.0.0.53</span></span></code></pre></div><p>这样，<code>company.internal</code> 以及其所有子域名（如 <code>api.company.internal</code>）都会通过 <code>10.0.0.53</code> 解析；<code>github.com</code> 等其他域名仍使用系统默认 DNS。</p><h2 id="创建配置" tabindex="-1">创建配置 <a class="header-anchor" href="#创建配置" aria-label="Permalink to “创建配置”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolver</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolver/company.internal</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nameserver 10.0.0.53</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span></code></pre></div><p>确认配置内容：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolver/company.internal</span></span></code></pre></div><h2 id="匹配优先级" tabindex="-1">匹配优先级 <a class="header-anchor" href="#匹配优先级" aria-label="Permalink to “匹配优先级”">​</a></h2><p>规则按最长域名后缀匹配。假设存在以下两个文件：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/etc/resolver/company.internal</span></span>
<span class="line"><span>/etc/resolver/dev.company.internal</span></span></code></pre></div><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># /etc/resolver/company.internal</span></span>
<span class="line"><span>nameserver 10.0.0.53</span></span></code></pre></div><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># /etc/resolver/dev.company.internal</span></span>
<span class="line"><span>nameserver 10.0.0.54</span></span></code></pre></div><p>则 <code>www.company.internal</code> 使用 <code>10.0.0.53</code>，而 <code>api.dev.company.internal</code> 同时匹配两条规则，会优先使用更具体的 <code>dev.company.internal</code> 规则，即 <code>10.0.0.54</code>。</p><h2 id="常用配置项" tabindex="-1">常用配置项 <a class="header-anchor" href="#常用配置项" aria-label="Permalink to “常用配置项”">​</a></h2><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>nameserver 10.0.0.53</span></span>
<span class="line"><span>nameserver 10.0.0.54</span></span>
<span class="line"><span>port 53</span></span>
<span class="line"><span>timeout 5</span></span>
<span class="line"><span>options attempts:2</span></span></code></pre></div><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td><code>nameserver</code></td><td>DNS 服务器地址</td></tr><tr><td><code>port</code></td><td>DNS 端口，默认为 <code>53</code></td></tr><tr><td><code>timeout</code></td><td>查询超时时间</td></tr><tr><td><code>options attempts:2</code></td><td>查询尝试次数</td></tr><tr><td><code>search</code></td><td>补全短主机名；不用于域名分流</td></tr></tbody></table><p>通常只需要设置一个或多个 <code>nameserver</code>。</p><h2 id="本地-dns-示例" tabindex="-1">本地 DNS 示例 <a class="header-anchor" href="#本地-dns-示例" aria-label="Permalink to “本地 DNS 示例”">​</a></h2><p>若本地 DNS 服务监听在 <code>127.0.0.1:5353</code>，可创建 <code>/etc/resolver/test</code>：</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>nameserver 127.0.0.1</span></span>
<span class="line"><span>port 5353</span></span></code></pre></div><p>之后，<code>api.test</code>、<code>mysql.test</code> 等域名都会交由本机 <code>5353</code> 端口上的 DNS 服务解析。</p><h2 id="验证与排查" tabindex="-1">验证与排查 <a class="header-anchor" href="#验证与排查" aria-label="Permalink to “验证与排查”">​</a></h2><p>查看系统当前加载的 DNS 配置，并定位目标规则：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scutil</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dns</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scutil</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dns</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;company.internal&#39;</span></span></code></pre></div><p>使用系统解析器测试：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dscacheutil</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.company.internal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.company.internal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.company.internal</span></span></code></pre></div><p><code>dig</code> 和 <code>nslookup</code> 不一定走 macOS 的系统 DNS 解析链路，因此不能只依据它们判断 <code>/etc/resolver</code> 是否生效。</p><h2 id="删除与缓存刷新" tabindex="-1">删除与缓存刷新 <a class="header-anchor" href="#删除与缓存刷新" aria-label="Permalink to “删除与缓存刷新”">​</a></h2><p>删除规则：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolver/company.internal</span></span></code></pre></div><p>如果仍受到旧缓存影响，刷新 DNS 缓存：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dscacheutil</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -flushcache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> killall</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -HUP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mDNSResponder</span></span></code></pre></div><h2 id="与-linux-etc-resolv-conf-的区别" tabindex="-1">与 Linux <code>/etc/resolv.conf</code> 的区别 <a class="header-anchor" href="#与-linux-etc-resolv-conf-的区别" aria-label="Permalink to “与 Linux /etc/resolv.conf 的区别”">​</a></h2><p>Linux 的 <code>/etc/resolv.conf</code> 一般用于配置全局默认 DNS：</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>nameserver 1.1.1.1</span></span>
<span class="line"><span>nameserver 8.8.8.8</span></span></code></pre></div><p>它通常不像 macOS 的 <code>/etc/resolver/</code> 一样按域名分流。Linux 若需实现分域 DNS，可使用 <code>systemd-resolved</code>、NetworkManager 或 DNS 转发工具。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li>文件名使用域名，不需要为每个完整主机名单独建文件。</li><li>子域名会自动匹配，且更具体的域名规则优先。</li><li>避免创建 <code>/etc/resolver/local</code>；<code>.local</code> 通常由 Bonjour/mDNS 使用，可能产生冲突。</li><li><code>/etc/resolver/</code> 只影响 DNS 解析，不负责代理、路由或端口转发。</li></ol>`,43)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};